/**
 * @author fengweiyao
 * @核心模块，负责计算需要更新的空间，并返回最新的文案，更新本地缓存。
 * 核心的步骤：
 * 1. 获取本地所有空间缓存的 version ，请求接口获取更新的文案
 * 2. 针对没有更新的空间，从本地获取文案
 * 3. 按照 format 对应格式，返回文案。
 *
 * 之所以单独抽离这个模块，是为了方便单元测试。
 */
import { Request } from './Request';
import { LocalCache } from './LocalCache';
import { Texts, Namspae, Options } from './options';
export declare type Result = {
    texts: Texts;
    diffNs: Array<Namspae>;
    equalNs: Array<Namspae>;
};
export interface Namespace {
    namespace: string;
    prior: number;
    version?: string;
    texts?: Texts;
    lang?: string;
}
export declare class NamespaceGroup {
    private _list;
    constructor(list?: Array<Namespace>);
    get length(): number;
    getList(): Namespace[];
    getNamespaces(): string[];
    addNamespace(ns: Namespace): void;
    insertTexts(textsArr: Array<Texts>): void;
    sortByPrior(): Namespace[];
    concat(nsg: NamespaceGroup): NamespaceGroup;
}
declare type LoadResult = {
    texts: Texts;
    diffNs: Array<string>;
    equalNs: Array<string>;
};
